package com.fasterxml.jackson.dataformat.xml.ser;

import org.junit.runner.RunWith;
import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "com.fasterxml.jackson.dataformat.xml.ser.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
    // This class serves as the Cucumber JUnit runner
}

package com.fasterxml.jackson.dataformat.xml.ser.steps;

import com.fasterxml.jackson.dataformat.xml.XmlMapper;
import io.cucumber.java8.En;
import static org.junit.Assert.*;

import java.io.ByteArrayOutputStream;
import java.nio.ByteBuffer;

public class StepDefs implements En {

    private Object pojo;
    private String xmlResult;

    public StepDefs() {
        Given("a POJO with a field \"field\" of type ByteBuffer", () -> {
            // Create a POJO with ByteBuffer field
            pojo = new TestPojo();
        });

        Given("the ByteBuffer is empty \\(contains 0 bytes\\)", () -> {
            // Set an empty ByteBuffer in the POJO
            ((TestPojo) pojo).field = ByteBuffer.allocate(0);
        });

        Given("the ByteBuffer is a DirectByteBuffer \\(which triggers stream-based processing\\)", () -> {
            // Create a direct ByteBuffer with 0 bytes
            ((TestPojo) pojo).field = ByteBuffer.allocateDirect(0);
        });

        When("the POJO is serialized to XML", () -> {
            try {
                XmlMapper xmlMapper = new XmlMapper();
                ByteArrayOutputStream baos = new ByteArrayOutputStream();
                xmlMapper.writeValue(baos, pojo);
                xmlResult = baos.toString();
            } catch (Exception e) {
                // Capture the exception, if any
                xmlResult = "EXCEPTION: " + e.getMessage();
            }
        });

        Then("the resulting XML should be \"<TestPojo><field/>\\</TestPojo>\"", () -> {
            String expected = "<TestPojo><field/></TestPojo>";
            assertEquals("XML output should match expected result", expected, xmlResult);
        });
    }

    // Inner class representing the POJO with a ByteBuffer field
    public static class TestPojo {
        public ByteBuffer field;
    }
}

